#include<iostream>
using namespace std;
int t,n,a,cot,f[1002][3000],len=1,lenlen[1002];
void gj(int k) {
	for(int i=1; i<=len; i++) {
		f[k][i]=f[k-1][i]*k;
	}
	for(int i=1; i<=len; i++) {
		if(f[k][i]>9) {
			f[k][i+1]+=f[k][i]/10;
			f[k][i]%=10;
		}
	}
	while(f[k][len+1]) {
		len++;
		f[k][len+1]+=f[k][len]/10;
		f[k][len]%=10;
	}
	lenlen[k]=len;
}
void check() {
	for(int i=1; i<=lenlen[n]; i++) {
		if(f[n][i]==a) {
			cot++;
		}
	}
}
int main() {
	cin>>t;
	f[0][1]=f[1][1]=1;
	for(int i=2; i<=1001; i++) {
		gj(i);
	}
	while(t--) {
		cin>>n>>a;
		cot=0;
		check();
		cout<<cot<<endl;
	}
	return 0;
}
